--[[\n    Dark Theme UI - Modern dark theme UI matching the style in the reference image\n]]\n\nlocal UILibrary = loadstring(game:HttpGet(\"https://raw.githubusercontent.com/dudu69doglei93829327jb095n4b3n/ui-library/main/src/init.lua\"))()\n\nlocal screen = UILibrary.Screen.new()\nscreen.frame.BackgroundColor3 = Color3.fromRGB(20, 20, 20)\nscreen.frame.BackgroundTransparency = 0\n\nlocal mainContainer = UILibrary.Panel.new({\n    parent = screen.frame,\n    position = UDim2.new(0, 0, 0, 0),\n    size = UDim2.new(1, 0, 1, 0),\n    backgroundColor = Color3.fromRGB(20, 20, 20)\n})\nmainContainer.frame.BackgroundTransparency = 0\n\nlocal leftSidebar = UILibrary.Panel.new({\n    parent = mainContainer.frame,\n    position = UDim2.new(0, 0, 0, 0),\n    size = UDim2.new(0, 180, 1, 0),\n    backgroundColor = Color3.fromRGB(30, 30, 30)\n})\nleftSidebar.frame.BackgroundTransparency = 0\n\nlocal logo = UILibrary.Label.new({\n    parent = leftSidebar.frame,\n    text = \"⬡\",\n    position = UDim2.new(0.5, -20, 0, 20),\n    size = UDim2.new(0, 40, 0, 40),\n    textSize = 32,\n    textColor = Color3.fromRGB(0, 150, 255),\n    backgroundTransparency = 1\n})\n\nlocal logoLabel = UILibrary.Label.new({\n    parent = leftSidebar.frame,\n    text = \"polygon\",\n    position = UDim2.new(0, 10, 0, 65),\n    size = UDim2.new(1, -20, 0, 20),\n    textSize = 14,\n    textColor = Color3.fromRGB(200, 200, 200),\n    backgroundTransparency = 1\n})\n\nlocal menuItems = {\"aim\", \"visuals\", \"misc\", \"config\", \"lua\"}\nfor i, item in ipairs(menuItems) do\n    local menuLabel = UILibrary.Label.new({\n        parent = leftSidebar.frame,\n        text = item,\n        position = UDim2.new(0, 10, 0, 95 + (i - 1) * 25),\n        size = UDim2.new(1, -20, 0, 20),\n        textSize = 13,\n        textColor = item == \"aim\" and Color3.fromRGB(0, 150, 255) or Color3.fromRGB(150, 150, 150),\n        backgroundTransparency = 1\n    })\nend\n\nlocal contentArea = UILibrary.Panel.new({\n    parent = mainContainer.frame,\n    position = UDim2.new(0, 180, 0, 0),\n    size = UDim2.new(1, -180, 1, 0),\n    backgroundColor = Color3.fromRGB(25, 25, 25)\n})\ncontentArea.frame.BackgroundTransparency = 0\n\nlocal tabsPanel = UILibrary.Panel.new({\n    parent = contentArea.frame,\n    position = UDim2.new(0, 0, 0, 0),\n    size = UDim2.new(1, 0, 0, 40),\n    backgroundColor = Color3.fromRGB(20, 20, 20)\n})\ntabsPanel.frame.BackgroundTransparency = 0\n\nlocal tabs = {\"players\", \"world\", \"items\", \"stash\"}\nfor i, tab in ipairs(tabs) do\n    local tabLabel = UILibrary.Label.new({\n        parent = tabsPanel.frame,\n        text = tab,\n        position = UDim2.new(0, 30 + (i - 1) * 100, 0, 10),\n        size = UDim2.new(0, 80, 0, 20),\n        textSize = 13,\n        textColor = tab == \"players\" and Color3.fromRGB(0, 150, 255) or Color3.fromRGB(150, 150, 150),\n        backgroundTransparency = 1\n    })\nend\n\nlocal leftPanel = UILibrary.Panel.new({\n    parent = contentArea.frame,\n    position = UDim2.new(0, 20, 0, 60),\n    size = UDim2.new(0, 270, 0, 400),\n    backgroundColor = Color3.fromRGB(30, 30, 30)\n})\nleftPanel.frame.BackgroundTransparency = 0\n\nlocal optionsTitle = UILibrary.Label.new({\n    parent = leftPanel.frame,\n    text = \"Options\",\n    position = UDim2.new(0, 10, 0, 10),\n    size = UDim2.new(1, -20, 0, 20),\n    textSize = 14,\n    textColor = Color3.fromRGB(200, 200, 200),\n    backgroundTransparency = 1\n})\n\nlocal checkboxes = {\"Enemy ESP\", \"Maximum Range\", \"Name\", \"Box\", \"Skeleton\", \"Flags\"}\nfor i, name in ipairs(checkboxes) do\n    local checkbox = UILibrary.Checkbox.new({\n        parent = leftPanel.frame,\n        text = name,\n        position = UDim2.new(0, 10, 0, 35 + (i - 1) * 30),\n        size = UDim2.new(1, -20, 0, 25),\n        checked = i <= 3\n    })\n    checkbox.box.BackgroundColor3 = Color3.fromRGB(0, 150, 255)\n    checkbox.box.TextColor3 = Color3.fromRGB(255, 255, 255)\n    checkbox.label.TextColor3 = Color3.fromRGB(200, 200, 200)\nend\n\nlocal rangeLabel = UILibrary.Label.new({\n    parent = leftPanel.frame,\n    text = \"Maximum Range\",\n    position = UDim2.new(0, 10, 0, 225),\n    size = UDim2.new(0.5, -15, 0, 20),\n    textSize = 12,\n    textColor = Color3.fromRGB(200, 200, 200),\n    backgroundTransparency = 1\n})\n\nlocal rangeValue = UILibrary.Label.new({\n    parent = leftPanel.frame,\n    text = \"400m\",\n    position = UDim2.new(0.5, 5, 0, 225),\n    size = UDim2.new(0.5, -15, 0, 20),\n    textSize = 12,\n    textColor = Color3.fromRGB(150, 150, 150),\n    backgroundTransparency = 1\n})\n\nlocal rightPanel = UILibrary.Panel.new({\n    parent = contentArea.frame,\n    position = UDim2.new(0, 310, 0, 60),\n    size = UDim2.new(0, 280, 0, 400),\n    backgroundColor = Color3.fromRGB(30, 30, 30)\n})\nrightPanel.frame.BackgroundTransparency = 0\n\nlocal previewTitle = UILibrary.Label.new({\n    parent = rightPanel.frame,\n    text = \"Preview\",\n    position = UDim2.new(0, 10, 0, 10),\n    size = UDim2.new(1, -20, 0, 20),\n    textSize = 14,\n    textColor = Color3.fromRGB(200, 200, 200),\n    backgroundTransparency = 1\n})\n\nlocal previewViewport = UILibrary.Panel.new({\n    parent = rightPanel.frame,\n    position = UDim2.new(0, 10, 0, 40),\n    size = UDim2.new(1, -20, 1, -60),\n    backgroundColor = Color3.fromRGB(15, 15, 15)\n})\npreviewViewport.frame.BackgroundTransparency = 0\n\nlocal previewLabel = UILibrary.Label.new({\n    parent = previewViewport.frame,\n    text = \"OPponent\\n1000\\nHP\\nESP K/D\\nUESC\",\n    position = UDim2.new(0, 10, 0, 10),\n    size = UDim2.new(1, -20, 1, -20),\n    textSize = 11,\n    textColor = Color3.fromRGB(0, 255, 100),\n    backgroundTransparency = 1\n})\n\nprint(\"Modern Dark Theme UI loaded successfully!\")\n